def lcs(a, b):
    m, n = len(a), len(b)
    dp = [[0]*(n+1) for _ in range(m+1)]
    for i in range(1, m+1):
        for j in range(1, n+1):
            if a[i-1] == b[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])
    return dp[m][n]

assert lcs('abcde', 'ace') == 3
assert lcs('abc', 'def') == 0
assert lcs('abc', 'abc') == 3
assert lcs('', 'abc') == 0
assert lcs('abcbdab', 'bdcab') == 4
