class Stack:
    def __init__(self):
        self._data = []
    def push(self, val):
        self._data.append(val)
    def pop(self):
        if not self._data:
            raise IndexError('pop from empty stack')
        return self._data.pop()
    def peek(self):
        if not self._data:
            raise IndexError('peek from empty stack')
        return self._data[-1]
    def is_empty(self):
        return len(self._data) == 0
    def size(self):
        return len(self._data)

s = Stack()
assert s.is_empty()
s.push(1); s.push(2); s.push(3)
assert s.size() == 3
assert s.peek() == 3
assert s.pop() == 3
assert s.pop() == 2
assert s.size() == 1
try:
    Stack().pop()
    assert False
except IndexError:
    pass
